import React, { useState } from "react";

export default function QuestionStep({ dimension, onComplete }) {
  const [phase, setPhase] = useState("intro"); 
  // intro → question → result
  const [result, setResult] = useState(null);

  const handleAnswer = (value) => {
    setResult(value);
    setPhase("result");
  };

  const question = dimension.questions[0];

  return (
    <div className="test-card">

      {/* ===== INTRO PHASE ===== */}
      {phase === "intro" && (
        <>
          <h2>{dimension.title}</h2>

          <p
            style={{
              fontSize: "16px",
              lineHeight: "1.6",
              color: "#b0bec5",
              margin: "26px 0 36px"
            }}
          >
            {dimension.intro}
          </p>

          <button onClick={() => setPhase("question")}>
            დაიწყე
          </button>
        </>
      )}

      {/* ===== QUESTION PHASE ===== */}
      {phase === "question" && (
        <>
          <p style={{ marginBottom: "24px" }}>
            {question.text}
          </p>

          <div style={{ display: "flex", gap: "20px" }}>
            <button onClick={() => handleAnswer(question.a.value)}>
              {question.a.text}
            </button>
            <button onClick={() => handleAnswer(question.b.value)}>
              {question.b.text}
            </button>
          </div>
        </>
      )}

      {/* ===== RESULT PHASE ===== */}
      {phase === "result" && (
        <>
          <img
            src={`/images/${result}.png`}
            alt={result}
            style={{ maxWidth: "150px", marginBottom: "20px" }}
          />

          <p style={{ marginBottom: "30px" }}>
            {dimension.descriptions[result]}
          </p>

          <button onClick={() => onComplete(result)}>
            განაგრძე →
          </button>
        </>
      )}

    </div>
  );
}
